// Submit the site's URLs to IndexNow so Bing + Yandex (re)crawl them within hours
// instead of weeks. Yandex is a major engine in Kazakhstan — exactly where this
// project competes — so this is the highest-leverage off-page lever we can automate.
// (Google does NOT support IndexNow; for Google rely on Search Console + the sitemap.)
//
// Our sitemap is generated by Next at request time, so this script FETCHES the live
// sitemap (not a static file) and submits every <loc> on our host. The key file
// public/<KEY>.txt MUST already be live at https://thediamond.kz/<KEY>.txt — IndexNow
// fetches it to verify ownership. So a real submit only works AFTER deploy.
//
// Usage:
//   node scripts/submit-indexnow.mjs --dry-run     # fetch sitemap, print, no submit
//   node scripts/submit-indexnow.mjs               # actually submit (post-deploy)
//   SITE_URL=https://thediamond.kz node scripts/submit-indexnow.mjs

const HOST = process.env.INDEXNOW_HOST ?? "thediamond.kz";
const KEY = process.env.INDEXNOW_KEY ?? "5c30e797358a85168747c318a156626c";
const SITE_URL = (process.env.SITE_URL ?? `https://${HOST}`).replace(/\/$/, "");
const SITEMAP_URL = process.env.SITEMAP_URL ?? `${SITE_URL}/sitemap.xml`;
const KEY_LOCATION = `${SITE_URL}/${KEY}.txt`;
const ENDPOINT = "https://api.indexnow.org/indexnow"; // fans out to Bing, Yandex, Seznam…
const MAX_URLS_PER_BATCH = 10000;

const dryRun = process.argv.includes("--dry-run");

const readSitemapUrls = async () => {
  const res = await fetch(SITEMAP_URL, { headers: { accept: "application/xml" } });
  if (!res.ok) throw new Error(`sitemap fetch failed: HTTP ${res.status} (${SITEMAP_URL})`);
  const xml = await res.text();
  const urls = [...xml.matchAll(/<loc>([^<]+)<\/loc>/g)].map((m) => m[1].trim());
  // IndexNow rejects the whole batch if any URL is off-host.
  return [...new Set(urls)].filter((u) => u.startsWith(`${SITE_URL}/`) || u === SITE_URL);
};

const chunk = (arr, size) => {
  const out = [];
  for (let i = 0; i < arr.length; i += size) out.push(arr.slice(i, i + size));
  return out;
};

const submitBatch = async (urlList) => {
  const res = await fetch(ENDPOINT, {
    method: "POST",
    headers: { "Content-Type": "application/json; charset=utf-8" },
    body: JSON.stringify({ host: HOST, key: KEY, keyLocation: KEY_LOCATION, urlList }),
  });
  return res.status;
};

(async () => {
  const urls = await readSitemapUrls();
  console.log(`IndexNow: ${urls.length} URLs from ${SITEMAP_URL}`);
  console.log(`  host=${HOST}  keyLocation=${KEY_LOCATION}`);

  if (dryRun) {
    console.log("  --dry-run — no request sent. Sample:");
    urls.slice(0, 8).forEach((u) => console.log("   ", u));
    console.log(`  (batches that would be sent: ${chunk(urls, MAX_URLS_PER_BATCH).length})`);
    return;
  }

  const batches = chunk(urls, MAX_URLS_PER_BATCH);
  for (let i = 0; i < batches.length; i += 1) {
    const status = await submitBatch(batches[i]);
    // 200/202 = accepted. 403 = key not found/invalid (is <KEY>.txt deployed?).
    // 422 = URLs don't match host/key. 429 = too many requests.
    const ok = status === 200 || status === 202;
    console.log(`  batch ${i + 1}/${batches.length}: ${batches[i].length} urls → HTTP ${status} ${ok ? "OK" : "CHECK"}`);
    if (!ok) process.exitCode = 1;
  }
})().catch((error) => {
  console.error("IndexNow submit failed:", error.message ?? error);
  process.exit(1);
});
